import { createClient } from "@supabase/supabase-js";

const SUPABASE_URL = typeof process !== "undefined" ? process.env.NEXT_PUBLIC_SUPABASE_URL : null;
const SUPABASE_ANON_KEY = typeof process !== "undefined" ? process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY : null;
const supabase = SUPABASE_URL && SUPABASE_ANON_KEY ? createClient(SUPABASE_URL, SUPABASE_ANON_KEY) : null;

// ============================================================================
// AeroLeadAI — Property Intelligence Mission Control (DEPLOYABLE VERSION)
// Differences from the artifact version:
//   • All Claude calls go through server routes (/api/damage-agent,
//     /api/verify-agent, /api/snow-verify) — key stays server-side
//   • Weather Analyst calls /api/weather-agent — this is the actual fix for
//     the Snow Load bug. The artifact sandbox blocks browser fetches to
//     arbitrary domains (only api.anthropic.com is allowed), which is why
//     NWS calls always failed there. Server-to-server has no such limit.
//   • temperature: 0 on every Claude call (set server-side) to cut down the
//     run-to-run score variance seen in testing (e.g. Tree Supervisor
//     scoring the same photo 38 one run, 65 the next)
//   • Persistence uses localStorage — SUPABASE SWAP POINT marked below
// ============================================================================

