function uid() { return Math.random().toString(36).slice(2, 10); }
function nowIso() { return new Date().toISOString(); }
function fileToBase64(file) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(r.result.split(",")[1]);
    r.onerror = () => rej(new Error("read failed"));
    r.readAsDataURL(file);
  });
}

// Resizes/compresses an image before sending to any AI provider. Roof/tree/
// driveway damage is visible well under full phone-camera resolution, and
// this cuts vision token usage substantially — important on Groq's free
// tier, still a good idea on Claude to keep costs down.
function compressImage(file, maxDim = 900, quality = 0.75) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    const reader = new FileReader();
    reader.onload = (e) => { img.src = e.target.result; };
    reader.onerror = reject;
    img.onload = () => {
      let { width, height } = img;
      if (width > maxDim || height > maxDim) {
        if (width > height) { height = Math.round(height * (maxDim / width)); width = maxDim; }
        else { width = Math.round(width * (maxDim / height)); height = maxDim; }
      }
      const canvas = document.createElement("canvas");
      canvas.width = width; canvas.height = height;
      canvas.getContext("2d").drawImage(img, 0, 0, width, height);
      const dataUrl = canvas.toDataURL("image/jpeg", quality);
      resolve({ dataUrl, base64: dataUrl.split(",")[1], mediaType: "image/jpeg" });
    };
    img.onerror = reject;
    reader.readAsDataURL(file);
  });
}
function levelFromScore(score) {
  if (score >= 75) return "severe";
  if (score >= 50) return "high";
  if (score >= 25) return "moderate";
  return "low";
}

// ---------------------------------------------------------------------------
// Storage: Supabase if NEXT_PUBLIC_SUPABASE_URL / _ANON_KEY are set (see
// README for the one-time table SQL), otherwise localStorage automatically.
// Requires a table: propintel_state (key text primary key, value text,
// user_id uuid). Row-level security should restrict rows to auth.uid().
// ---------------------------------------------------------------------------
const storage = {
  async get(key) {
    if (supabase) {
      try {
        const { data: userData } = await supabase.auth.getUser();
        const uid = userData?.user?.id;
        let query = supabase.from("propintel_state").select("value").eq("key", key);
        if (uid) query = query.eq("user_id", uid);
        const { data, error } = await query.maybeSingle();
        if (error) throw error;
        if (data) return { value: data.value };
      } catch {
        // fall through to localStorage
      }
    }
    try { const v = localStorage.getItem(key); return v ? { value: v } : null; } catch { return null; }
  },
  async set(key, value) {
    if (supabase) {
      try {
        const { data: userData } = await supabase.auth.getUser();
        const uid = userData?.user?.id;
        const { error } = await supabase.from("propintel_state").upsert({ key, value, user_id: uid || null });
        if (error) throw error;
        return { key, value };
      } catch {
        // fall through to localStorage
      }
    }
    try { localStorage.setItem(key, value); return { key, value }; } catch { return null; }
  },
};

// ---------------------------------------------------------------------------
// Server route callers
// ---------------------------------------------------------------------------
async function runAnalyst(domain, images, address) {
  // images: array of {base64Image, mediaType}. Single-image callers can still
  // pass a 1-length array — this stopped taking one flat image because the
  // multi-angle imagery sweep produces several relevant shots per property
  // that were previously being fetched and then silently discarded.
  const res = await fetch("/api/damage-agent", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ domain, images, address }),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error);
  return data;
}

async function runAnalystAveraged(domain, images, address, onRunLog) {
  const first = await runAnalyst(domain, images, address);

  // Multi-run averaging triples token usage per analysis — Groq's free tier
  // (30,000 tokens/minute) can't absorb that across a 4-supervisor scan.
  // Only average on Claude, where the paid tier has real headroom for it.
  if (first.provider === "groq") return { finding: first, runs: 1 };

  const borderline = first.confidence === "low" || (first.concern_score >= 20 && first.concern_score <= 80);
  if (!borderline) return { finding: first, runs: 1 };

  const second = await runAnalyst(domain, images, address);
  const third = await runAnalyst(domain, images, address);
  const scores = [first.concern_score, second.concern_score, third.concern_score];
  const avg = Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
  const mergedIndicators = [...new Set([...(first.indicators || []), ...(second.indicators || []), ...(third.indicators || [])])];
  if (onRunLog) onRunLog(scores);
  return {
    finding: {
      concern_score: avg,
      indicators: mergedIndicators,
      confidence: scores.every((s) => Math.abs(s - avg) <= 10) ? "medium" : "low",
      notes: `Averaged across 3 runs (${scores.join(", ")}) — ${first.notes}`,
      level: levelFromScore(avg),
      provider: first.provider,
    },
    runs: 3,
  };
}

async function runVerification(domain, base64Image, mediaType, finding) {
  const res = await fetch("/api/verify-agent", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ domain, base64Image, mediaType, finding }),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error);
  return data;
}

async function runWeatherAnalyst(lat, lon) {
  const res = await fetch("/api/weather-agent", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ lat, lon }),
  });
  return res.json();
}

function runStructuralAnalyst(weather, buildingAge, roofPitch) {
  // Still a rule-based estimate — no real load rating, snow-water-equivalent,
  // or engineering data source wired in. Roof pitch now factors in because
  // low-slope roofs hold snow load far longer than steep ones, which is one
  // of the biggest real drivers of actual risk.
  let score = 10;
  if (weather.snowPeriods >= 3) score += 35;
  else if (weather.snowPeriods >= 1) score += 15;
  const age = Number(buildingAge) || 0;
  if (age >= 40) score += 25;
  else if (age >= 20) score += 12;
  const pitch = (roofPitch || "").toLowerCase();
  if (pitch.includes("low")) score += 15;
  else if (pitch.includes("steep")) score -= 10;
  score = Math.max(0, Math.min(100, score));
  return { concern_score: score, level: levelFromScore(score), confidence: "low", notes: "Rule-based estimate (weather + age + pitch) — not a substitute for a structural engineer." };
}

async function runSnowVerification(weatherSummary, structural) {
  const res = await fetch("/api/snow-verify", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ weatherSummary, structural }),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error);
  return data;
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------
export default function PropertyIntelligenceConsole() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [passwordInput, setPasswordInput] = useState("");
  const [loginError, setLoginError] = useState(false);
  const [authChecked, setAuthChecked] = useState(false);
  const [magicEmail, setMagicEmail] = useState("");
  const [magicSent, setMagicSent] = useState(false);
  const [magicError, setMagicError] = useState(null);

  const [properties, setProperties] = useState({});
  const [currentId, setCurrentId] = useState(null);
  const [loaded, setLoaded] = useState(false);

  const [addrDraft, setAddrDraft] = useState({ address: "", lat: "", lon: "", parcelId: "", permitId: "", roofType: "", buildingAge: "", roofPitch: "" });
  const [geocoding, setGeocoding] = useState(false);
  const [creatingProperty, setCreatingProperty] = useState(false);
  const [geocodeError, setGeocodeError] = useState(null);
  const [statuses, setStatuses] = useState({});
  const [memory, setMemory] = useState({});
  const [selectedAgent, setSelectedAgent] = useState(null);
  const [running, setRunning] = useState(false);

  const fileRefs = { roof: useRef(null), tree: useRef(null), driveway: useRef(null) };

  useEffect(() => {
    if (!supabase) { setAuthChecked(true); return; }
    supabase.auth.getSession().then(({ data }) => {
      if (data?.session) setLoggedIn(true);
      setAuthChecked(true);
    });
    const { data: sub } = supabase.auth.onAuthStateChange((_event, session) => {
      setLoggedIn(!!session);
    });
    return () => sub?.subscription?.unsubscribe();
  }, []);

  async function sendMagicLink() {
    if (!magicEmail || !supabase) return;
    setMagicError(null);
    const { error } = await supabase.auth.signInWithOtp({ email: magicEmail });
    if (error) setMagicError(error.message);
    else setMagicSent(true);
  }

  useEffect(() => {
    (async () => {
      try { const p = await storage.get("propintel:properties"); if (p?.value) setProperties(JSON.parse(p.value)); } catch {}
      try { const m = await storage.get("propintel:memory"); if (m?.value) setMemory(JSON.parse(m.value)); } catch {}
      setLoaded(true);
    })();
  }, []);

  const persistProperties = useCallback(async (next) => {
    setProperties(next);
    await storage.set("propintel:properties", JSON.stringify(next));
  }, []);

  const persistMemory = useCallback(async (next) => {
    setMemory(next);
    await storage.set("propintel:memory", JSON.stringify(next));
  }, []);

  function blankFolders() {
    return { images: [], drone: [], street: [], historical: [], weather: [], permits: [], inspectionReports: [], contractorNotes: [], aiFindings: [], repairs: [], timeline: [] };
  }

  async function geocodeAddress() {
    if (!addrDraft.address) return;
    setGeocoding(true);
    setGeocodeError(null);
    const q = addrDraft.address.trim();
    const isZipOnly = /^\d{5}$/.test(q);

    try {
      if (isZipOnly) {
        // ZIP-only input: resolve to the ZIP's centroid via Zippopotam (accurate, free)
        const zRes = await fetch(`https://api.zippopotam.us/us/${q}`);
        if (zRes.ok) {
          const z = await zRes.json();
          const place = z.places?.[0];
          if (place) {
            setAddrDraft((d) => ({ ...d, lat: place.latitude, lon: place.longitude }));
            setGeocoding(false);
            return;
          }
        }
        setGeocodeError("ZIP not found — enter a full address or lat/lon manually.");
        setGeocoding(false);
        return;
      }

      // Full address: Census Bureau geocoder first — built specifically for US
      // street addresses and is materially more accurate than Nominatim for this.
      const censusRes = await fetch(
        `https://geocoding.geo.census.gov/geocoder/locations/onelineaddress?address=${encodeURIComponent(q)}&benchmark=Public_AR_Current&format=json`
      );
      if (censusRes.ok) {
        const cd = await censusRes.json();
        const match = cd?.result?.addressMatches?.[0];
        if (match?.coordinates) {
          setAddrDraft((d) => ({ ...d, lat: String(match.coordinates.y), lon: String(match.coordinates.x) }));
          setGeocoding(false);
          return;
        }
      }

      // Fallback: Nominatim (covers non-US-standard formatting Census misses)
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q)}`, {
        headers: { "Accept-Language": "en" },
      });
      const data = await res.json();
      if (data && data.length > 0) {
        setAddrDraft((d) => ({ ...d, lat: data[0].lat, lon: data[0].lon }));
      } else {
        setGeocodeError("No match found — enter lat/lon manually.");
      }
    } catch (e) {
      setGeocodeError("Lookup failed — enter lat/lon manually.");
    }
    setGeocoding(false);
  }

  async function fetchImageryFor(lat, lon) {
    try {
      const res = await fetch("/api/imagery-agent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ lat, lon }),
      });
      const data = await res.json();
      const shots = [];
      if (data.dataUrl) {
        shots.push({ id: uid(), kind: "overview", dataUrl: data.dataUrl, uploadedAt: nowIso(), source: `auto-fetched (${data.provider})` });
      }
      // Save every swept Street View vantage/heading as its own shot so the
      // full multi-angle coverage is kept, not just the front-facing one.
      if (data.angles) {
        for (const [key, dataUrl] of Object.entries(data.angles)) {
          if (key === "overview") continue;
          shots.push({ id: uid(), kind: key, dataUrl, uploadedAt: nowIso(), source: "street-view sweep" });
        }
      }
      return shots;
    } catch (e) {
      return [];
    }
  }

  async function fetchPermitsFor(address) {
    try {
      const res = await fetch(`/api/permit-lookup?address=${encodeURIComponent(address)}`);
      const data = await res.json();
      if (data.ok && data.inDirectory && data.records?.length) {
        return data.records.map((r) => ({
          id: uid(), at: nowIso(),
          text: `[Directory] ${r.permit_type || "Permit"} — ${r.issue_date || "date unknown"}${r.roof_related ? " (roof-related)" : ""}${r.notes ? " — " + r.notes : ""}`,
        }));
      }
      return [];
    } catch (e) {
      return [];
    }
  }

  // ---------- AUTONOMOUS BATCH PIPELINE ----------
  // Paste addresses, press one button. Per address: geocode → satellite tile →
  // permit directory (10-year rule) → damage agent on the fetched tile → scored
  // property. Human touches nothing unless a stage fails, in which case the
  // property is still created and flagged with exactly what needs manual help.
  const [batchText, setBatchText] = useState("");
  const [batchRunning, setBatchRunning] = useState(false);
  const [batchLog, setBatchLog] = useState([]);
  const [batchProgress, setBatchProgress] = useState({ done: 0, total: 0 });

  function logBatch(line) { setBatchLog((l) => [...l, line]); }

  async function runBatchIntake() {
    const addresses = batchText.split("\n").map((a) => a.trim()).filter(Boolean);
    if (!addresses.length || batchRunning) return;
    setBatchRunning(true);
    setBatchLog([]);
    setBatchProgress({ done: 0, total: addresses.length });
    let propsAccum = { ...properties };

    for (const address of addresses) {
      const id = uid();
      let lat = "", lon = "", needsHuman = [];
      logBatch(`▶ ${address}`);

      // 1. Geocode
      try {
        const geo = await (await fetch("/api/geocode", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ address }) })).json();
        if (geo.ok) { lat = geo.lat; lon = geo.lon; logBatch(`   geocoded via ${geo.provider}`); }
        else { needsHuman.push("geocode"); logBatch(`   ⚠ geocode failed — add lat/lon manually`); }
      } catch (e) { needsHuman.push("geocode"); logBatch(`   ⚠ geocode error`); }

      // 2. Imagery
      let street = [], roofImage = null;
      if (lat && lon) {
        try {
          const img = await (await fetch("/api/imagery-agent", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ lat, lon }) })).json();
          if (img.dataUrl) {
            street = [{ id: uid(), kind: "overview", dataUrl: img.dataUrl, uploadedAt: nowIso(), source: `auto-fetched (${img.provider})` }];
            roofImage = { id: uid(), domain: "roof", dataUrl: img.dataUrl, mediaType: img.dataUrl.slice(5, img.dataUrl.indexOf(";")), uploadedAt: nowIso(), source: "auto-fetched satellite" };
            logBatch(`   imagery fetched (${img.provider})`);
          } else { needsHuman.push("imagery"); logBatch(`   ⚠ ${img.notes || img.error || "no imagery"}`); }
        } catch (e) { needsHuman.push("imagery"); logBatch(`   ⚠ imagery error`); }
      }

      // 3. Permits + 10-year rule
      let permits = [], lowPriority = false, lowPriorityReason = null;
      try {
        const pr = await (await fetch(`/api/permit-lookup?address=${encodeURIComponent(address)}`)).json();
        if (pr.ok && pr.inDirectory) {
          permits = pr.records.map((r) => ({ id: uid(), at: nowIso(), text: `[Directory] ${r.permit_type || "Permit"} — ${r.issue_date || "date unknown"}${r.roof_related ? " (roof-related)" : ""}` }));
          if (pr.lowPriority) { lowPriority = true; lowPriorityReason = pr.lowPriorityReason; logBatch(`   ⬇ ${pr.lowPriorityReason}`); }
          else logBatch(`   permits: ${pr.records.length} on file, none within 10 years`);
        } else logBatch(`   permits: ${pr.notes}`);
      } catch (e) { logBatch(`   ⚠ permit lookup error`); }

      // 4. Damage scoring on the fetched tile (skipped if deprioritized — no
      //    point spending vision tokens on a lead the 10-year rule already sank)
      let findingsScore = null, aiFindings = [];
      if (roofImage && !lowPriority) {
        try {
          const base64 = roofImage.dataUrl.split(",")[1];
          const { finding, runs } = await runAnalystAveraged("roof", base64, roofImage.mediaType, address);
          findingsScore = finding.concern_score;
          aiFindings = [{ id: uid(), at: nowIso(), results: { roof: finding }, findingsScore, source: `batch auto-scan (${runs} run${runs > 1 ? "s" : ""}, ${finding.provider})` }];
          logBatch(`   damage score ${findingsScore} (${finding.level})`);
        } catch (e) { needsHuman.push("scoring"); logBatch(`   ⚠ scoring failed: ${e.message}`); }
      } else if (lowPriority) {
        findingsScore = 0;
        logBatch(`   scoring skipped — deprioritized by permit rule`);
      }

      const prop = {
        id, address, lat, lon,
        parcelId: "", permitId: "", roofType: "", buildingAge: "", roofPitch: "",
        createdAt: nowIso(),
        folders: { ...blankFolders(), street, images: roofImage ? [roofImage] : [], permits, aiFindings },
        findingsScore, suggestedActions: [],
        lowPriority, lowPriorityReason,
        needsHuman: needsHuman.length ? needsHuman : null,
      };
      propsAccum = { ...propsAccum, [id]: prop };
      await persistProperties(propsAccum);
      setBatchProgress((p) => ({ ...p, done: p.done + 1 }));
    }

    logBatch(`✔ Batch complete — ${addresses.length} properties processed.`);
    setBatchRunning(false);
  }

  // ---------- IMAGE ENHANCEMENT (zoom calibration / edit / enhance) ----------
  // Pure canvas, no dependencies. Zoom is a center-crop re-render (calibrated
  // zoom-in on the roof), enhance applies brightness/contrast plus a 3x3
  // sharpen convolution — the standard trio for making shingle damage readable.
  const [enhanceTarget, setEnhanceTarget] = useState(null); // { folder, imageId }
  const [enhanceParams, setEnhanceParams] = useState({ zoom: 1, brightness: 0, contrast: 0, sharpen: false });
  const [enhancePreview, setEnhancePreview] = useState(null);

  function applyEnhancement(dataUrl, { zoom, brightness, contrast, sharpen }) {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = img.width; canvas.height = img.height;
        const ctx = canvas.getContext("2d");

        // Zoom calibration: center-crop by zoom factor, scale back to full size
        const cw = img.width / zoom, ch = img.height / zoom;
        const cx = (img.width - cw) / 2, cy = (img.height - ch) / 2;
        ctx.filter = `brightness(${100 + brightness}%) contrast(${100 + contrast}%)`;
        ctx.drawImage(img, cx, cy, cw, ch, 0, 0, canvas.width, canvas.height);
        ctx.filter = "none";

        if (sharpen) {
          const src = ctx.getImageData(0, 0, canvas.width, canvas.height);
          const dst = ctx.createImageData(canvas.width, canvas.height);
          const k = [0, -1, 0, -1, 5, -1, 0, -1, 0];
          const w = canvas.width, h = canvas.height, sd = src.data, dd = dst.data;
          for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
              for (let c = 0; c < 3; c++) {
                let acc = 0;
                for (let ky = -1; ky <= 1; ky++) {
                  for (let kx = -1; kx <= 1; kx++) {
                    const px = Math.min(w - 1, Math.max(0, x + kx));
                    const py = Math.min(h - 1, Math.max(0, y + ky));
                    acc += sd[(py * w + px) * 4 + c] * k[(ky + 1) * 3 + (kx + 1)];
                  }
                }
                dd[(y * w + x) * 4 + c] = Math.min(255, Math.max(0, acc));
              }
              dd[(y * w + x) * 4 + 3] = sd[(y * w + x) * 4 + 3];
            }
          }
          ctx.putImageData(dst, 0, 0);
        }
        resolve(canvas.toDataURL("image/jpeg", 0.92));
      };
      img.src = dataUrl;
    });
  }

  async function previewEnhancement() {
    if (!enhanceTarget || !current) return;
    const image = current.folders[enhanceTarget.folder].find((i) => i.id === enhanceTarget.imageId);
    if (!image) return;
    const out = await applyEnhancement(image.dataUrl, enhanceParams);
    setEnhancePreview(out);
  }

  async function saveEnhancement() {
    if (!enhanceTarget || !current || !enhancePreview) return;
    const folder = current.folders[enhanceTarget.folder].map((i) =>
      i.id === enhanceTarget.imageId ? { ...i, dataUrl: enhancePreview, enhanced: true } : i
    );
    const nextProp = { ...current, folders: { ...current.folders, [enhanceTarget.folder]: folder } };
    await persistProperties({ ...properties, [current.id]: nextProp });
    addTimeline(current.id, `Image enhanced (zoom ${enhanceParams.zoom}x, brightness ${enhanceParams.brightness}, contrast ${enhanceParams.contrast}${enhanceParams.sharpen ? ", sharpened" : ""}).`);
    setEnhanceTarget(null); setEnhancePreview(null);
    setEnhanceParams({ zoom: 1, brightness: 0, contrast: 0, sharpen: false });
  }

  async function createProperty() {
    if (!addrDraft.address) return;
    setCreatingProperty(true);
    const id = uid();
    let street = [];
    let permits = [];
    if (addrDraft.lat && addrDraft.lon) {
      street = await fetchImageryFor(addrDraft.lat, addrDraft.lon);
    }
    permits = await fetchPermitsFor(addrDraft.address);
    const prop = {
      id, ...addrDraft, createdAt: nowIso(),
      folders: { ...blankFolders(), street, permits },
      findingsScore: null, suggestedActions: [],
    };
    await persistProperties({ ...properties, [id]: prop });
    setCurrentId(id);
    setAddrDraft({ address: "", lat: "", lon: "", parcelId: "", permitId: "", roofType: "", buildingAge: "", roofPitch: "" });
    setCreatingProperty(false);
  }

  function demoOverviewImage() { return `data:image/jpeg;base64,${DEMO_OVERVIEW_B64}`; }
  function demoRoofImage() { return `data:image/jpeg;base64,${DEMO_ROOF_B64}`; }
  function demoTreeImage() { return `data:image/jpeg;base64,${DEMO_TREE_B64}`; }
  function demoDrivewayImage() { return `data:image/jpeg;base64,${DEMO_DRIVEWAY_B64}`; }

  async function loadDemoProperty() {
    const id = uid();
    const overview = { id: uid(), kind: "overview", dataUrl: demoOverviewImage(), uploadedAt: nowIso() };
    const roof = { id: uid(), domain: "roof", dataUrl: demoRoofImage(), mediaType: "image/jpeg", uploadedAt: nowIso() };
    const driveway = { id: uid(), domain: "driveway", dataUrl: demoDrivewayImage(), mediaType: "image/jpeg", uploadedAt: nowIso() };
    const tree = { id: uid(), domain: "tree", dataUrl: demoTreeImage(), mediaType: "image/jpeg", uploadedAt: nowIso() };
    const prop = {
      id, address: "4243 13th Ave S, Minneapolis, MN 55407", lat: "44.9285", lon: "-93.2456",
      parcelId: "", permitId: "", roofType: "Asphalt shingle", buildingAge: "80", roofPitch: "Moderate",
      createdAt: nowIso(),
      folders: { ...blankFolders(), images: [roof, tree, driveway], street: [overview] },
      findingsScore: null, suggestedActions: [],
    };
    await persistProperties({ ...properties, [id]: prop });
    setCurrentId(id);
  }

  const current = currentId ? properties[currentId] : null;

  function setStatus(agentId, status) { setStatuses((s) => ({ ...s, [agentId]: status })); }

  function logMemory(agentId, entry) {
    setMemory((prev) => {
      const existing = prev[agentId] || { confidenceHistory: [], errorRate: 0, avgProcessingTimeMs: 0, runs: 0, lastUpdate: null, costIncurred: 0 };
      const runs = existing.runs + 1;
      const avg = Math.round((existing.avgProcessingTimeMs * existing.runs + entry.processingTimeMs) / runs);
      const next = {
        ...prev,
        [agentId]: {
          confidenceHistory: [entry.confidence, ...existing.confidenceHistory].slice(0, 20),
          errorRate: existing.errorRate, avgProcessingTimeMs: avg, runs, lastUpdate: nowIso(),
          lastEvidence: entry.evidence, lastImages: entry.images || [],
          costIncurred: (existing.costIncurred || 0) + (entry.cost || 0),
        },
      };
      persistMemory(next);
      return next;
    });
  }

  async function uploadImage(domain, e) {
    const f = e.target.files?.[0];
    if (!f || !current) return;
    const { dataUrl, mediaType } = await compressImage(f);
    const entry = { id: uid(), domain, dataUrl, mediaType, uploadedAt: nowIso() };
    const nextProp = { ...current, folders: { ...current.folders, images: [entry, ...current.folders.images] } };
    persistProperties({ ...properties, [current.id]: nextProp });
  }

  function addTimeline(propId, text) {
    setProperties((prev) => {
      const p = prev[propId];
      if (!p) return prev;
      const next = { ...p, folders: { ...p.folders, timeline: [{ id: uid(), text, at: nowIso() }, ...p.folders.timeline] } };
      const updated = { ...prev, [propId]: next };
      persistProperties(updated);
      return updated;
    });
  }

  async function runDomainSupervisor(domain) {
    const scoutId = `${domain}-scout`, analystId = `${domain}-analyst`, verifyId = `${domain}-verify`;
    const manualImages = current.folders.images.filter((im) => im.domain === domain);

    setStatus(scoutId, "working");
    await new Promise((r) => setTimeout(r, 150));

    // Build the full set of images actually worth scoring for this domain,
    // instead of grabbing one and discarding the rest of the sweep:
    //  - any manually uploaded photos for this domain (highest trust)
    //  - the tight satellite crop (best top-down view for roof/driveway)
    //  - for roof specifically: the roofline-pitched street view shots, since
    //    that's the one angle in the sweep actually aimed at the roof surface
    //  - if nothing at all exists, fall back to an auto-enhanced satellite crop
    let scoreSet = manualImages.map((im) => ({ base64Image: im.dataUrl.split(",")[1], mediaType: im.mediaType, ref: im }));

    const street = current.folders.street || [];
    const tight = street.find((s) => s.kind === "overview_tight" || s.kind === "overview");
    if (tight) scoreSet.push({ base64Image: tight.dataUrl.split(",")[1], mediaType: "image/jpeg", ref: tight });

    if (domain === "roof") {
      const roofline = street.filter((s) => s.kind && s.kind.includes("roofline"));
      roofline.forEach((s) => scoreSet.push({ base64Image: s.dataUrl.split(",")[1], mediaType: "image/jpeg", ref: s }));
    }

    if (scoreSet.length === 0 && street.length > 0) {
      const sat = street[0];
      try {
        const enhanced = await applyEnhancement(sat.dataUrl, { zoom: 1.4, brightness: 108, contrast: 115, sharpen: true });
        const img = { id: uid(), domain, dataUrl: enhanced, mediaType: "image/jpeg", uploadedAt: nowIso(), source: "auto-enhanced satellite" };
        const nextProp = { ...current, folders: { ...current.folders, images: [...current.folders.images, img] } };
        await persistProperties({ ...properties, [current.id]: nextProp });
        addTimeline(current.id, `${DOMAIN_LABELS[domain]} Supervisor: using auto-enhanced satellite image for analysis.`);
        scoreSet.push({ base64Image: enhanced.split(",")[1], mediaType: "image/jpeg", ref: img });
      } catch (_) {}
    }

    if (scoreSet.length === 0) {
      setStatus(scoutId, "requesting");
      addTimeline(current.id, `${DOMAIN_LABELS[domain]} Supervisor: no images on file — requesting owner upload.`);
      return { domain, ok: false, reason: "no_images" };
    }
    const img = scoreSet[0].ref; // primary reference image, used for verification + memory log
    setStatus(scoutId, "idle");
    setStatus(analystId, "working");
    const t0 = performance.now();
    const { finding, runs: analystRuns } = await runAnalystAveraged(domain, scoreSet.map((s) => ({ base64Image: s.base64Image, mediaType: s.mediaType })), current.address);
    const t1 = performance.now();
    setStatus(analystId, "idle");
    logMemory(analystId, {
      confidence: finding.confidence,
      processingTimeMs: Math.round(t1 - t0),
      evidence: `${analystRuns > 1 ? `${finding.notes} (ran ${analystRuns}x for confidence)` : finding.notes} — scored across ${scoreSet.length} image(s)${finding.provider ? ` [${finding.provider}]` : ""}`,
      images: scoreSet.map((s) => s.ref.dataUrl),
      cost: 0.015 * analystRuns * scoreSet.length,
    });

    setStatus(verifyId, "working");
    const t2 = performance.now();
    const verification = await runVerification(domain, img.dataUrl.split(",")[1], img.mediaType, finding);
    const t3 = performance.now();
    const finalScore = verification.adjusted_score ?? finding.concern_score;
    setStatus(verifyId, verification.flag_for_human ? "review" : "idle");
    logMemory(verifyId, { confidence: verification.confidence, processingTimeMs: Math.round(t3 - t2), evidence: `${verification.note}${verification.provider ? ` [${verification.provider}]` : ""}`, images: [img.dataUrl], cost: 0.015 });

    addTimeline(current.id, `${DOMAIN_LABELS[domain]} Supervisor: concern score ${finalScore} (${levelFromScore(finalScore)})${verification.flag_for_human ? " — flagged for human review" : ""}.`);
    return { domain, ok: true, score: finalScore, level: levelFromScore(finalScore), finding, verification, flagged: !!verification.flag_for_human };
  }

  async function runSnowSupervisor() {
    setStatus("snow-weather", "working");
    const t0 = performance.now();
    const weather = current.lat && current.lon ? await runWeatherAnalyst(current.lat, current.lon) : { ok: false, summary: "No coordinates on file for this property.", snowPeriods: 0 };
    const t1 = performance.now();
    setStatus("snow-weather", weather.ok ? "idle" : "review");
    logMemory("snow-weather", { confidence: weather.ok ? "high" : "low", processingTimeMs: Math.round(t1 - t0), evidence: weather.summary, cost: 0 });

    setStatus("snow-structural", "working");
    const t2 = performance.now();
    const structural = runStructuralAnalyst(weather, current.buildingAge, current.roofPitch);
    const t3 = performance.now();
    setStatus("snow-structural", "idle");
    logMemory("snow-structural", { confidence: structural.confidence, processingTimeMs: Math.round(t3 - t2), evidence: structural.notes, cost: 0 });

    setStatus("snow-verify", "working");
    const t4 = performance.now();
    const verification = await runSnowVerification(weather.summary, structural);
    const t5 = performance.now();
    setStatus("snow-verify", verification.flag_for_human ? "review" : "idle");
    logMemory("snow-verify", { confidence: verification.agrees ? "medium" : "low", processingTimeMs: Math.round(t5 - t4), evidence: verification.note, cost: 0.01 });

    addTimeline(current.id, `Snow Load Supervisor: concern score ${structural.concern_score} (${structural.level}) — ${weather.summary}${verification.flag_for_human ? " — flagged for human review" : ""}.`);
    return { domain: "snow", ok: true, score: structural.concern_score, level: structural.level, weather, structural, verification, flagged: !!verification.flag_for_human };
  }

  async function runFullScan() {
    if (!current) return;
    setRunning(true);
    setStatus("ops", "working");

    const results = [];
    for (const domain of ["roof", "tree", "driveway"]) {
      results.push(await runDomainSupervisor(domain));
      await new Promise((r) => setTimeout(r, 2500)); // pace requests to stay under free-tier rate limits
    }
    results.push(await runSnowSupervisor());
    setStatus("ops", "idle");

    const scored = results.filter((r) => r.ok);
    const missing = results.filter((r) => !r.ok);
    const avgConcern = scored.length ? Math.round(scored.reduce((s, r) => s + r.score, 0) / scored.length) : null;
    const findingsScore = avgConcern === null ? null : Math.max(0, 100 - avgConcern);

    const actions = [];
    scored.forEach((r) => {
      if (r.level === "severe" || r.level === "high") actions.push(`${DOMAIN_LABELS[r.domain] || "Snow Load"}: ${r.level} concern (score ${r.score}) — recommend inspection.`);
      if (r.flagged) actions.push(`${DOMAIN_LABELS[r.domain] || "Snow Load"}: verification flagged for human review.`);
    });
    missing.forEach((r) => actions.push(`${DOMAIN_LABELS[r.domain]}: no images on file — upload photos to complete this assessment.`));
    if (actions.length === 0) actions.push("No elevated concerns detected across available data.");

    const nextProp = {
      ...current, findingsScore, suggestedActions: actions,
      folders: { ...current.folders, aiFindings: [{ id: uid(), at: nowIso(), results, findingsScore }, ...current.folders.aiFindings] },
    };
    await persistProperties({ ...properties, [current.id]: nextProp });
    setRunning(false);
  }

  const [manualFolder, setManualFolder] = useState("permits");
  const [manualText, setManualText] = useState("");

  function addManualEntry() {
    if (!manualText || !current) return;
    const entry = { id: uid(), text: manualText, at: nowIso() };
    const nextProp = { ...current, folders: { ...current.folders, [manualFolder]: [entry, ...current.folders[manualFolder]] } };
    persistProperties({ ...properties, [current.id]: nextProp });
    addTimeline(current.id, `Manual entry added to ${manualFolder}: "${manualText}"`);
    setManualText("");
  }

  const agentDetail = selectedAgent ? memory[selectedAgent] : null;

  if (!authChecked) return null;

  if (!loggedIn) {
    return (
      <div style={{ position: "fixed", inset: 0, background: SLATE, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "Inter, system-ui, sans-serif" }}>
        <div style={{ background: PANEL, padding: 40, borderRadius: 16, width: 340, textAlign: "center", border: `1px solid ${LINE}` }}>
          <div style={{ fontSize: 11, letterSpacing: 2, color: AMBER, fontFamily: "monospace" }}>AEROLEADAI</div>
          <h1 style={{ color: "#dfe6ee", fontSize: 20, margin: "6px 0 16px" }}>Property Intelligence</h1>

          {supabase ? (
            magicSent ? (
              <p style={{ color: GREEN, fontSize: 13 }}>Check your email for a sign-in link.</p>
            ) : (
              <>
                <input
                  type="email"
                  value={magicEmail}
                  onChange={(e) => setMagicEmail(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && sendMagicLink()}
                  placeholder="you@company.com"
                  style={{ width: "100%", padding: 12, margin: "10px 0", background: PANEL2, border: `1px solid ${LINE}`, color: "#dfe6ee", borderRadius: 8, boxSizing: "border-box" }}
                />
                <button onClick={sendMagicLink} style={{ width: "100%", padding: 12, background: AMBER, color: "#1a1200", border: "none", borderRadius: 8, fontWeight: 700, cursor: "pointer" }}>
                  Send sign-in link
                </button>
                {magicError && <p style={{ color: SIGNAL, fontSize: 12, marginTop: 10 }}>{magicError}</p>}
              </>
            )
          ) : (
            <>
              <p style={{ color: MUTE, fontSize: 13 }}>Enter access code</p>
              <input
                type="password"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && (passwordInput === ACCESS_PASSWORD ? setLoggedIn(true) : setLoginError(true))}
                placeholder="Access code"
                style={{ width: "100%", padding: 12, margin: "10px 0", background: PANEL2, border: `1px solid ${LINE}`, color: "#dfe6ee", borderRadius: 8, boxSizing: "border-box" }}
              />
              <button
                onClick={() => (passwordInput === ACCESS_PASSWORD ? setLoggedIn(true) : setLoginError(true))}
                style={{ width: "100%", padding: 12, background: AMBER, color: "#1a1200", border: "none", borderRadius: 8, fontWeight: 700, cursor: "pointer" }}
              >
                Enter
              </button>
              {loginError && <p style={{ color: SIGNAL, fontSize: 12, marginTop: 10 }}>Wrong code — try again.</p>}
            </>
          )}
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: SLATE, color: "#dfe6ee", fontFamily: "Inter, system-ui, sans-serif" }}>
      <div style={{ borderBottom: `1px solid ${LINE}`, padding: "18px 20px", display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
        <div>
          <div style={{ fontSize: 12, letterSpacing: 2, color: AMBER, fontFamily: "monospace" }}>AEROLEADAI // MISSION CONTROL</div>
          <div style={{ fontSize: 20, fontWeight: 700, marginTop: 2 }}>Property Intelligence</div>
        </div>
        <a href="/batch" style={{ padding: "8px 14px", border: `1px solid ${LINE}`, borderRadius: 6, color: BLUE, fontSize: 13, textDecoration: "none" }}>Mass Upload / Batch pipeline →</a>
      </div>

      <div style={{ padding: 20, borderBottom: `1px solid ${LINE}` }}>
        <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>SEARCH / ADD PROPERTY</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 8, marginBottom: 6 }}>
          {[["address", "Address"], ["lat", "Lat"], ["lon", "Lon"], ["parcelId", "Parcel ID"], ["permitId", "Permit ID"], ["roofType", "Roof Type"], ["buildingAge", "Building Age (yrs)"], ["roofPitch", "Roof Pitch (Low/Moderate/Steep)"]].map(([key, label]) => (
            <input key={key} value={addrDraft[key]} onChange={(e) => setAddrDraft((d) => ({ ...d, [key]: e.target.value }))} placeholder={label}
              style={{ padding: "8px 10px", background: PANEL, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee", fontSize: 13 }} />
          ))}
        </div>
        <div style={{ marginBottom: 10 }}>
          <button onClick={geocodeAddress} disabled={geocoding || !addrDraft.address} style={{ padding: "6px 12px", background: "transparent", border: `1px solid ${LINE}`, borderRadius: 6, color: geocoding ? MUTE : BLUE, fontSize: 12, cursor: geocoding ? "default" : "pointer" }}>
            {geocoding ? "Looking up…" : "Find coordinates from address"}
          </button>
          {geocodeError && <span style={{ fontSize: 11, color: SIGNAL, marginLeft: 8 }}>{geocodeError}</span>}
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
          <button onClick={createProperty} disabled={creatingProperty || !addrDraft.address} style={{ padding: "8px 16px", background: creatingProperty ? MUTE : AMBER, color: "#1a1200", border: "none", borderRadius: 6, fontWeight: 700, cursor: creatingProperty ? "default" : "pointer" }}>
            {creatingProperty ? "Fetching imagery + permits…" : "Add Property"}
          </button>
          <button onClick={loadDemoProperty} style={{ padding: "8px 16px", background: "transparent", color: GREEN, border: `1px solid ${GREEN}`, borderRadius: 6, fontWeight: 700, cursor: "pointer" }}>Load Demo Property</button>
          {loaded && Object.keys(properties).length > 0 && (
            <select value={currentId || ""} onChange={(e) => setCurrentId(e.target.value || null)} style={{ padding: "8px 10px", background: PANEL, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee" }}>
              <option value="">Select property…</option>
              {Object.values(properties).map((p) => (<option key={p.id} value={p.id}>{p.lowPriority ? "⬇ " : p.needsHuman ? "⚠ " : ""}{p.address}{p.findingsScore !== null && p.findingsScore !== undefined ? ` — ${p.findingsScore}` : ""}</option>))}
            </select>
          )}
        </div>
      </div>

      <div style={{ padding: 20, borderBottom: `1px solid ${LINE}`, background: PANEL2 }}>
        <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 6 }}>BATCH INTAKE — AUTONOMOUS</div>
        <div style={{ fontSize: 12, color: MUTE, marginBottom: 10 }}>
          Paste addresses, one per line. Each runs the full pipeline unattended: geocode → satellite imagery → permit directory (anything permitted within 10 years is auto-deprioritized and skips vision scoring) → damage agent → scored property.
        </div>
        <textarea
          value={batchText}
          onChange={(e) => setBatchText(e.target.value)}
          placeholder={"4243 13th Ave S, Minneapolis, MN 55407\n1234 Example St, Shakopee, MN\n..."}
          rows={4}
          disabled={batchRunning}
          style={{ width: "100%", boxSizing: "border-box", padding: 10, background: PANEL, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee", fontSize: 13, fontFamily: "monospace", resize: "vertical" }}
        />
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginTop: 8 }}>
          <button onClick={runBatchIntake} disabled={batchRunning || !batchText.trim()} style={{ padding: "8px 16px", background: batchRunning ? LINE : AMBER, color: batchRunning ? MUTE : "#1a1200", border: "none", borderRadius: 6, fontWeight: 700, cursor: batchRunning ? "default" : "pointer" }}>
            {batchRunning ? `Processing ${batchProgress.done}/${batchProgress.total}…` : "Run Batch Pipeline"}
          </button>
          {batchProgress.total > 0 && !batchRunning && (
            <span style={{ fontSize: 12, color: GREEN }}>{batchProgress.done}/{batchProgress.total} processed</span>
          )}
        </div>
        {batchLog.length > 0 && (
          <pre style={{ marginTop: 10, maxHeight: 180, overflowY: "auto", background: SLATE, border: `1px solid ${LINE}`, borderRadius: 6, padding: 10, fontSize: 11, color: "#b9c4d0", whiteSpace: "pre-wrap" }}>
            {batchLog.join("\n")}
          </pre>
        )}
      </div>

      {enhanceTarget && current && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.75)", zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 12, padding: 20, maxWidth: 720, width: "100%", maxHeight: "90vh", overflowY: "auto" }}>
            <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>IMAGE ENHANCEMENT — ZOOM CALIBRATION / EDIT</div>
            <img
              src={enhancePreview || current.folders[enhanceTarget.folder].find((i) => i.id === enhanceTarget.imageId)?.dataUrl}
              alt="Enhancement preview"
              style={{ width: "100%", borderRadius: 8, border: `1px solid ${LINE}`, marginBottom: 12 }}
            />
            {[["zoom", "Zoom calibration", 1, 4, 0.25], ["brightness", "Brightness", -50, 50, 5], ["contrast", "Contrast", -50, 50, 5]].map(([key, label, min, max, step]) => (
              <div key={key} style={{ marginBottom: 8 }}>
                <label style={{ fontSize: 12, color: MUTE }}>{label}: <span style={{ color: "#dfe6ee" }}>{enhanceParams[key]}{key === "zoom" ? "x" : ""}</span></label>
                <input type="range" min={min} max={max} step={step} value={enhanceParams[key]}
                  onChange={(e) => setEnhanceParams((p) => ({ ...p, [key]: parseFloat(e.target.value) }))}
                  style={{ width: "100%" }} />
              </div>
            ))}
            <label style={{ fontSize: 12, color: MUTE, display: "block", marginBottom: 12 }}>
              <input type="checkbox" checked={enhanceParams.sharpen} onChange={(e) => setEnhanceParams((p) => ({ ...p, sharpen: e.target.checked }))} /> Sharpen (edge convolution — makes shingle granule loss readable)
            </label>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={previewEnhancement} style={{ padding: "8px 16px", background: "transparent", border: `1px solid ${BLUE}`, color: BLUE, borderRadius: 6, fontWeight: 700, cursor: "pointer" }}>Preview</button>
              <button onClick={saveEnhancement} disabled={!enhancePreview} style={{ padding: "8px 16px", background: enhancePreview ? AMBER : LINE, color: enhancePreview ? "#1a1200" : MUTE, border: "none", borderRadius: 6, fontWeight: 700, cursor: enhancePreview ? "pointer" : "default" }}>Save enhanced</button>
              <button onClick={() => { setEnhanceTarget(null); setEnhancePreview(null); setEnhanceParams({ zoom: 1, brightness: 0, contrast: 0, sharpen: false }); }} style={{ padding: "8px 16px", background: "transparent", border: `1px solid ${LINE}`, color: MUTE, borderRadius: 6, cursor: "pointer" }}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      {!current ? (
        <div style={{ padding: 40, textAlign: "center", color: MUTE }}>Add or select a property to begin.</div>
      ) : (
        <div style={{ padding: 20 }}>
          {current.lowPriority && (
            <div style={{ marginBottom: 12, padding: "10px 14px", background: "rgba(90,107,140,.15)", border: `1px solid ${LINE}`, borderRadius: 8, fontSize: 13, color: MUTE }}>
              ⬇ <b>Low priority</b> — {current.lowPriorityReason || "Permit pulled within the last 10 years."} Vision scoring was skipped to save tokens; run a manual scan if you want it anyway.
            </div>
          )}
          {current.needsHuman && (
            <div style={{ marginBottom: 12, padding: "10px 14px", background: "rgba(255,179,71,.1)", border: `1px solid ${AMBER}`, borderRadius: 8, fontSize: 13, color: AMBER }}>
              ⚠ Batch pipeline needs help on: <b>{current.needsHuman.join(", ")}</b> — everything else completed automatically.
            </div>
          )}
          {current.folders.street.length > 0 && (
            <div style={{ marginBottom: 16, borderRadius: 10, overflow: "hidden", border: `1px solid ${LINE}` }}>
              <img src={current.folders.street[0].dataUrl} alt="Property overview" style={{ width: "100%", maxHeight: 320, objectFit: "cover", display: "block" }} />
              <div style={{ padding: "8px 12px", background: PANEL, fontSize: 11, color: MUTE, fontFamily: "monospace" }}>Bird's-eye overview — {current.address}</div>
              {current.folders.street.length > 1 && (
                <div style={{ display: "flex", gap: 6, padding: "10px 12px", overflowX: "auto", background: "#0d1420" }}>
                  {current.folders.street.slice(1).map((shot) => (
                    <div key={shot.id} style={{ flexShrink: 0, width: 100 }}>
                      <img src={shot.dataUrl} alt={shot.kind} style={{ width: 100, height: 75, objectFit: "cover", borderRadius: 6, border: `1px solid ${LINE}` }} />
                      <div style={{ fontSize: 9, color: MUTE, textAlign: "center", marginTop: 3, fontFamily: "monospace" }}>{shot.kind.replace(/_/g, " ")}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 16, marginBottom: 16, flexWrap: "wrap", gap: 10 }}>
            <div>
              <div style={{ fontSize: 12, color: MUTE, fontFamily: "monospace" }}>FINDINGS</div>
              <div style={{ fontSize: 26, fontWeight: 700, color: current.findingsScore === null ? MUTE : current.findingsScore >= 75 ? GREEN : current.findingsScore >= 50 ? AMBER : SIGNAL }}>
                {current.findingsScore === null ? "—" : `${current.findingsScore}/100`}
              </div>
            </div>
            <button onClick={runFullScan} disabled={running} style={{ padding: "10px 20px", background: running ? LINE : AMBER, color: running ? MUTE : "#1a1200", border: "none", borderRadius: 6, fontWeight: 700, cursor: running ? "default" : "pointer" }}>
              {running ? "Running full scan…" : "Run Full Property Scan"}
            </button>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "minmax(240px, 320px) 1fr", gap: 16 }}>
            <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 14, alignSelf: "start" }}>
              <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>ACTIVE AGENTS</div>
              <div style={{ padding: "6px 8px", borderRadius: 6, background: PANEL2, marginBottom: 8, fontSize: 12, fontWeight: 700 }}>{STATUS[statuses["ops"] || "off"].dot} CEO Agent</div>
              {HIERARCHY.map((sup) => (
                <div key={sup.id} style={{ marginLeft: 10, marginBottom: 8 }}>
                  <div style={{ fontSize: 12, color: MUTE }}>{STATUS[statuses[sup.id] || "off"].dot} {sup.name}</div>
                  {sup.sub && (
                    <div style={{ marginLeft: 16, marginTop: 4, display: "grid", gap: 4 }}>
                      {sup.sub.map((a) => (
                        <button key={a.id} onClick={() => setSelectedAgent(a.id)}
                          style={{ textAlign: "left", fontSize: 11, padding: "4px 8px", borderRadius: 5, border: `1px solid ${selectedAgent === a.id ? AMBER : "transparent"}`, background: PANEL2, color: STATUS[statuses[a.id] || "off"].color, cursor: "pointer" }}>
                          {STATUS[statuses[a.id] || "off"].dot} {a.name}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              ))}
              {agentDetail && (
                <div style={{ marginTop: 14, borderTop: `1px solid ${LINE}`, paddingTop: 12 }}>
                  <div style={{ fontSize: 11, fontFamily: "monospace", color: AMBER, marginBottom: 6 }}>{selectedAgent}</div>
                  <div style={{ fontSize: 11, color: MUTE }}>Runs: {agentDetail.runs}</div>
                  <div style={{ fontSize: 11, color: MUTE }}>Avg time: {agentDetail.avgProcessingTimeMs}ms</div>
                  <div style={{ fontSize: 11, color: MUTE }}>Cost incurred: ${(agentDetail.costIncurred || 0).toFixed(3)}</div>
                  <div style={{ fontSize: 11, color: MUTE }}>Last confidence: {agentDetail.confidenceHistory?.[0] || "—"}</div>
                  <div style={{ fontSize: 11, color: MUTE, marginTop: 4 }}>Evidence: {agentDetail.lastEvidence}</div>
                  {agentDetail.lastImages?.[0] && <img src={agentDetail.lastImages[0]} alt="" style={{ width: "100%", borderRadius: 6, marginTop: 6 }} />}
                </div>
              )}
            </div>

            <div style={{ display: "grid", gap: 16 }}>
              <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 16 }}>
                <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>IMAGE INTAKE</div>
                <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                  {["roof", "tree", "driveway"].map((domain) => (
                    <div key={domain}>
                      <button onClick={() => fileRefs[domain].current?.click()} style={{ padding: "8px 14px", background: PANEL2, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee", cursor: "pointer", fontSize: 12 }}>
                        Upload {DOMAIN_LABELS[domain]} photo
                      </button>
                      <input ref={fileRefs[domain]} type="file" accept="image/*" onChange={(e) => uploadImage(domain, e)} style={{ display: "none" }} />
                    </div>
                  ))}
                </div>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 12 }}>
                  {current.folders.images.map((im) => (
                    <div key={im.id} onClick={() => { setEnhanceTarget({ folder: "images", imageId: im.id }); setEnhancePreview(null); }} style={{ cursor: "pointer" }} title="Click to zoom / edit / enhance">
                      <img src={im.dataUrl} alt="" style={{ width: 64, height: 64, objectFit: "cover", borderRadius: 6, border: im.enhanced ? `2px solid ${GREEN}` : "none" }} />
                      <div style={{ fontSize: 9, color: im.enhanced ? GREEN : MUTE, textAlign: "center" }}>{DOMAIN_LABELS[im.domain]}{im.enhanced ? " ✦" : ""}</div>
                    </div>
                  ))}
                  {current.folders.images.length === 0 && <div style={{ fontSize: 12, color: MUTE }}>No images yet — agents will request them when you run a scan.</div>}
                </div>
              </div>

              <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 16 }}>
                <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>SUGGESTED ACTIONS</div>
                {current.suggestedActions.length === 0 ? (
                  <div style={{ fontSize: 13, color: MUTE }}>Run a scan to generate recommendations.</div>
                ) : (
                  <ul style={{ margin: 0, paddingLeft: 18, fontSize: 13, color: "#dfe6ee" }}>{current.suggestedActions.map((a, i) => (<li key={i} style={{ marginBottom: 4 }}>{a}</li>))}</ul>
                )}
              </div>

              <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 16 }}>
                <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>PROPERTY DIRECTORY — {current.address}</div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(120px, 1fr))", gap: 8 }}>
                  {Object.entries(current.folders).map(([key, val]) => (
                    <div key={key} style={{ background: PANEL2, border: `1px solid ${LINE}`, borderRadius: 6, padding: "8px 10px" }}>
                      <div style={{ fontSize: 11, color: MUTE, textTransform: "capitalize" }}>{key.replace(/([A-Z])/g, " $1")}</div>
                      <div style={{ fontSize: 15, fontWeight: 700, color: AMBER }}>{val.length}</div>
                    </div>
                  ))}
                </div>
                <div style={{ marginTop: 14, borderTop: `1px solid ${LINE}`, paddingTop: 12 }}>
                  <div style={{ fontSize: 11, color: MUTE, marginBottom: 6 }}>
                    No live connector for permits, drone imagery, or historical records yet — that needs a chosen data vendor and API key. Log anything manually for now:
                  </div>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    <select value={manualFolder} onChange={(e) => setManualFolder(e.target.value)} style={{ padding: "6px 8px", background: PANEL2, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee", fontSize: 12 }}>
                      <option value="permits">Permits</option>
                      <option value="inspectionReports">Inspection Reports</option>
                      <option value="contractorNotes">Contractor Notes</option>
                      <option value="repairs">Repairs</option>
                    </select>
                    <input value={manualText} onChange={(e) => setManualText(e.target.value)} onKeyDown={(e) => e.key === "Enter" && addManualEntry()} placeholder="Note or record…" style={{ flex: 1, minWidth: 140, padding: "6px 10px", background: PANEL2, border: `1px solid ${LINE}`, borderRadius: 6, color: "#dfe6ee", fontSize: 12 }} />
                    <button onClick={addManualEntry} style={{ padding: "6px 14px", background: AMBER, color: "#1a1200", border: "none", borderRadius: 6, fontSize: 12, fontWeight: 700, cursor: "pointer" }}>Add</button>
                  </div>
                </div>
              </div>

              <div style={{ background: PANEL, border: `1px solid ${LINE}`, borderRadius: 10, padding: 16 }}>
                <div style={{ fontSize: 12, fontFamily: "monospace", color: AMBER, marginBottom: 10 }}>TIMELINE</div>
                {current.folders.timeline.length === 0 ? (
                  <div style={{ fontSize: 13, color: MUTE }}>No activity yet.</div>
                ) : (
                  <div style={{ display: "grid", gap: 6 }}>
                    {current.folders.timeline.slice(0, 12).map((t) => (
                      <div key={t.id} style={{ fontSize: 12, color: MUTE }}>
                        <span style={{ color: "#dfe6ee" }}>{t.text}</span>
                        <div style={{ fontSize: 10 }}>{new Date(t.at).toLocaleString()}</div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <div style={{ padding: "14px 20px", borderTop: `1px solid ${LINE}`, fontSize: 11, color: MUTE, fontFamily: "monospace" }}>
        Weather Analyst calls NWS server-side (fixes the artifact-sandbox bug) · Structural Analyst is a rule-based placeholder · temperature 0 on all Claude calls for consistent scoring
      </div>
    </div>
  );
}
